B.Tb=s(["extends","implements","with","interface"],t.s)
B.PL=new A.aE("b_dart_4","dart_fundamentals","OOP",B.aB,B.ds,"Which keyword is used to implement an interface in Dart?","implements",'Dart has no explicit "interface" keyword. Every class implicitly defines an interface. Use "implements" to implement it, which requires overriding all methods.',B.Tb,1)
B.P7=new A.aE("b_dart_5","dart_fundamentals","Collections",B.aB,B.B,"What are the main collection types in Dart?","List (ordered, allows duplicates), Set (unordered, no duplicates), and Map (key-value pairs).",'List<int> numbers = [1, 2, 3];\nSet<String> unique = {"a", "b"};\nMap<String, int> ages = {"Alice": 30};',null,null)
B.Pa=new A.aE("b_widget_1","widgets","StatelessWidget",B.aB,B.B,"What is the difference between StatelessWidget and StatefulWidget?","StatelessWidget is immutable \u2014 its build method depends only on its constructor arguments. StatefulWidget has mutable State that can change over time, triggering rebuilds via setState.","Use StatelessWidget when the UI depends only on the input data. Use StatefulWidget when the widget needs to manage internal state that changes (e.g., a counter, form inputs).",null,null)
B.Q7=new A.aE("b_widget_2","widgets","Lifecycle",B.aB,B.B,"What is the widget lifecycle in Flutter?","For StatefulWidget: createState() \u2192 initState() \u2192 didChangeDependencies() \u2192 build() \u2192 didUpdateWidget() \u2192 setState() \u2192 dispose().","initState is called once when inserted into the tree. build is called whenever the state changes. dispose is called when permanently removed.",null,null)
B.PX=new A.aE("b_widget_3","widgets","BuildContext",B.aB,B.B,"What is BuildContext in Flutter?","BuildContext is a handle to the location of a widget in the widget tree. It is used to look up inherited widgets, navigate, show dialogs, and access theme/media query data.","Every widget's build method receives a BuildContext. It represents where THIS widget sits in the tree and allows traversal upward to find ancestors like Theme, MediaQuery, or Navigator.",null,null)
B.RN=s(["build()","initState()","didChangeDependencies()","createState()"],t.s)
B.PH=new A.aE("b_widget_4","widgets","StatefulWidget",B.aB,B.ds,"Which method is called when a StatefulWidget is first inserted into the widget tree?","initState()","createState() creates the State object. initState() is the first method called on that State object after creation, before the first build().",B.RN,1)
B.Pg=new A.aE("b_widget_5","widgets","Keys",B.aB,B.B,"What are Keys in Flutter and when should you use them?","Keys uniquely identify widgets to preserve state when widgets move in the tree. Use them in lists, when reordering items, or when you need to preserve state across rebuilds.","Without keys, Flutter matches widgets by type and position. If you reorder a list, the state stays at the old position. Keys (ValueKey, ObjectKey, UniqueKey) fix this.",null,null)
B.Pl=new A.aE("b_layout_1","layouts","Flex",B.aB,B.B,"What is the difference between Row and Column in Flutter?","Row lays out children horizontally (main axis = horizontal). Column lays out children vertically (main axis = vertical). Both use the flex layout model.","MainAxisAlignment controls spacing along the main axis. CrossAxisAlignment controls alignment on the cross axis. Both accept mainAxisSize to control how much space they take.",null,null)
B.PC=new A.aE("b_layout_2","layouts","Constraints",B.aB,B.B,'Explain Flutter\'s layout model: "Constraints go down. Sizes go up. Parent sets position."',"Parent widgets pass constraints (min/max width and height) down to children. Children choose their size within those constraints. The parent then decides where to position each child.","This is the fundamental layout rule. A Container in an unconstrained environment has no size. In a constrained one, it fills the constraints unless given an explicit size.",null,null)
B.Sf=s(["SizedBox","Expanded","Padding","Center"],t.s)
B.PP=new A.aE("b_layout_3","layouts","Constraints",B.aB,B.ds,"Which widget makes its child fill all available space?","Expanded","Expanded tells a Flex (Row/Column) child to fill all remaining space. Flexible is similar but doesn't force the child to fill the space.",B.Sf,1)
B.PS=new A.aE("b_state_1","state_management","setState",B.aB,B.B,"What does setState() do in Flutter?","setState() marks the State as dirty, scheduling a rebuild. The framework calls build() again with the updated state, and efficiently patches the UI.","Always modify state variables inside the setState callback. Calling setState outside of a mounted State throws an error. It only rebuilds the widget that owns that State.",null,null)
B.Pm=new A.aE("b_state_2","state_management","InheritedWidget",B.aB,B.B,"What is InheritedWidget and why is it important?","InheritedWidget efficiently propagates data down the widget tree without passing it through constructors. It is the foundation for Theme, MediaQuery, and state management solutions like Provider.","Widgets below an InheritedWidget can access its data via context. When the InheritedWidget changes, all dependents are rebuilt. This is how Theme.of(context) works.",null,null)
B.PO=new A.aE("b_nav_1","navigation","Navigator 1.0",B.aB,B.B,"How does navigation work in Flutter?","Flutter uses a Navigator widget that manages a stack of Route objects. push() adds a route to the stack. pop() removes the top route. Named routes use pushNamed().","Navigator.push(context, MaterialPageRoute(builder: (_) => NextScreen()));\nNavigator.pop(context);\nThe Navigator manages a stack \u2014 the top route is what the user sees.",null,null)
B.Sg=s(["Navigator.push()","Navigator.pop()","Navigator.replace()","Navigator.remove()"],t.s)
B.Q6=new A.aE("b_nav_2","navigation","Navigator 1.0",B.aB,B.ds,"Which method removes the current screen and returns to the previous one?","Navigator.pop()",null,B.Sg,1)
B.Pi=new A.aE("b_net_1","networking","HTTP",B.aB,B.B,"How do you make an HTTP request in Flutter?","Use the http package: http.get(Uri.parse(url)), which returns a Future<Response>. Parse the response body (usually JSON) with jsonDecode().",'final response = await http.get(Uri.parse("https://api.example.com/data"));\nif (response.statusCode == 200) {\n  final data = jsonDecode(response.body);\n}',null,null)
B.PF=new A.aE("b_net_2","networking","JSON",B.aB,B.B,"How do you parse JSON in Dart?","Use dart:convert's jsonDecode() to convert JSON string to Map/List. For typed models, create a factory fromJson constructor and a toJson method.","Manual: Map<String, dynamic> data = jsonDecode(jsonString);\nTyped: User.fromJson(data).\nFor code generation: use json_serializable package.",null,null)
B.PM=new A.aE("b_test_1","testing","Unit Tests",B.aB,B.B,"What are the three types of tests in Flutter?","Unit tests (test individual functions/classes), Widget tests (test individual widgets), and Integration tests (test the full app or large sections).","Unit tests are fastest and cheapest. Widget tests render widgets in a test environment. Integration tests run on a real device/emulator. The testing pyramid recommends more unit tests, fewer integration tests.",null,null)
B.Pf=new A.aE("b_misc_1","widgets","StatelessWidget",B.aB,B.B,"What is hot reload and how is it different from hot restart?","Hot reload injects updated source code into the running Dart VM, preserving app state. Hot restart recompiles the entire app and resets all state.","Hot reload works by updating the widget tree without losing navigation state, scroll position, etc. It only works with certain changes \u2014 structural changes to initState or main() require hot restart.",null,null)
