B.Sl=s(["True","False"],t.s)
B.Qc=new A.aE("b_misc_2","dart_fundamentals","Types",B.aB,B.ht,"Dart is a statically typed language.","True","Dart is statically typed with type inference. The analyzer checks types at compile time, but you can use dynamic to opt out of static checking.",B.Sl,0)
B.Pb=new A.aE("b_misc_3","layouts","Themes",B.aB,B.B,"How do you apply a consistent theme across a Flutter app?","Pass a ThemeData to MaterialApp's theme parameter. Access it anywhere via Theme.of(context). Override locally with Theme widget.","MaterialApp(theme: ThemeData(colorScheme: ColorScheme.fromSeed(seedColor: Colors.blue)));\nAccess: Theme.of(context).colorScheme.primary",null,null)
